import React from 'react';

import Lottie from 'lottie-react-native';

import LoadingDeterminate from '../../../assets/animations/determinate-loading.json';
import LoadingIndeterminate from '../../../assets/animations/indeterminate-loading.json';
import { Box, BoxModal } from '../../atoms/Box';
import { Text } from '../../atoms/Text';
import normalize from '../../constants/normalize';
import { PropsLoading } from './Models';

export default function Modal({
  title,
  visible = false,
  description,
  speedLoading = 1,
  testID,
  loadingProgress,
  isDeterminated = false,
}: PropsLoading) {
  return (
    <BoxModal visible={visible} animationType="fade" transparent>
      <Box
        width="100%"
        height="100%"
        align="center"
        justify="center"
        pd="innerLarge"
        bgColor="OPACITY_COLOR_01"
        testID={testID}
      >
        <Box
          align="center"
          justify="center"
          bgColor="INTENSE_COLOR_01"
          br="large"
          pd="innerLarge"
        >
          <Lottie
            testID="DS-Core-Lottie-Loading"
            source={isDeterminated ? LoadingDeterminate : LoadingIndeterminate}
            autoPlay={!isDeterminated}
            loop={!isDeterminated}
            progress={isDeterminated ? loadingProgress : undefined}
            style={{
              width: normalize(26),
              height: normalize(26),
            }}
            speed={isDeterminated ? speedLoading : 1}
          />
          {title && (
            <Text
              mt="xxxxs"
              type="paragraphXL"
              align="center"
              color="BRAND_COMPLEMENT_01"
            >
              {title}
            </Text>
          )}
          {description && (
            <Text
              mt="xxxxs"
              type="paragraphMD"
              align="center"
              color="INTENSE_COLOR_03"
            >
              {description}
            </Text>
          )}
        </Box>
      </Box>
    </BoxModal>
  );
}

