import React, { forwardRef } from 'react';
import { View } from 'react-native';

const Modalize = forwardRef(({ children }: any, _ref: any) => (
  <View>{children}</View>
));

Modalize.displayName = 'Modalize';

export default Modalize;
export { Modalize };

import React from 'react';
import { View } from 'react-native';

function SkeletonPlaceholder({ children }: any) {
  return <View>{children}</View>;
}

function Item(props: any) {
  return <View style={props.style} />;
}

SkeletonPlaceholder.Item = Item;

export default SkeletonPlaceholder;

import React from 'react';
import { View } from 'react-native';

function Slider(_props: any) {
  return <View style={{ height: 40, backgroundColor: '#ddd' }} />;
}

export default Slider;

import React from 'react';
import { View } from 'react-native';

function LottieView(props: any) {
  return <View style={[{ width: 50, height: 50 }, props.style]} />;
}

export default LottieView;

